# create_default_* ----
## Setup ----
data <- FIMS::FIMSFrame(data1)

default_configurations <- create_default_configurations(data)

vonb_configurations <- default_configurations |>
  tidyr::unnest(cols = data) |>
  dplyr::rows_update(
    tibble::tibble(
      module_name = "Growth",
      module_type = "VonBertalanffy"
    ),
    by = c("module_name")
  )

# create_default_parameters ----
## IO correctness ----
test_that("`create_default_parameters()` works with correct inputs", {
  result <- create_default_parameters(
    configurations = default_configurations,
    data = data
  )
  result_unnested <- result |>
    tidyr::unnest(cols = data)

  #' @description Test that the main output is a `tbl_df`.
  expect_s3_class(result, "tbl_df")
  #' @description Test that the main output table has the correct column structure.
  expect_equal(
    colnames(result),
    c("model_family", "module_name", "fleet_name", "data")
  )
  #' @description Test that the `data` column is structured to hold nested information.
  expect_true(is.list(result[["data"]]))
  #' @description Test that the nested information within the `data` column is also a `tbl_df`.
  expect_s3_class(result[["data"]][[1]], "tbl_df")
  #' @description Test that the nested data table has the correct column structure.
  expect_equal(
    colnames(result[["data"]][[1]]),
    c(
      "module_type", "label", "distribution_link", "age", "length", "time",
      "value", "estimation_type", "distribution_type", "distribution"
    )
  )
  #' @description Test that the generated parameter values have not changed from the accepted snapshot.
  expect_snapshot_file(
    save_csv(result_unnested),
    "default_parameters.csv",
    compare = compare_file_text
  )
})

test_that("default VonB growth parameters use delta-method variability defaults", {
  growth_defaults <- create_default_parameters(
    configurations = vonb_configurations,
    data = data
  ) |>
    tidyr::unnest(cols = data) |>
    dplyr::filter(
      module_name == "Growth",
      module_type == "VonBertalanffy"
    )

  delta_method_variability_labels <- c(
    "log_sd_length_at_ref_age_1",
    "log_sd_length_at_ref_age_2",
    "log_sd_growth_coefficient_K",
    "logit_corr_length_at_ref_age_1_length_at_ref_age_2",
    "logit_corr_length_at_ref_age_1_k",
    "logit_corr_length_at_ref_age_2_k"
  )

  #' @description Test that default VonB growth parameters include the
  #' delta-method variability block.
  expect_true(all(delta_method_variability_labels %in% growth_defaults$label))

  #' @description Test that legacy interpolation SD-anchor defaults are no longer
  #' part of the default VonB growth parameter table.
  expect_false("length_at_age_sd_at_ref_ages" %in% growth_defaults$label)
})

